# Create a simple p5.js generative art sketch
# This will be a colorful particle system with your trading theme

html_content = '''<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Crypto Flow - Generative Art</title>
    <script>p5.disableFriendlyErrors = true;</script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/p5.js/1.11.3/p5.min.js"></script>
    <style>
        html, body { margin: 0; padding: 0; overflow: hidden; background: #0a0a0f; }
        canvas { display: block; }
    </style>
</head>
<body>
<script>
// === Configuration ===
const CONFIG = {
    particleCount: 150,
    noiseScale: 0.008,
    speed: 2,
    trailAlpha: 15
};

// === Color Palette (Crypto Theme) ===
const PALETTE = [
    '#F7931A', // Bitcoin Orange
    '#627EEA', // Ethereum Blue
    '#26A17B', // Tether Green
    '#FFD700', // Gold
    '#00D4FF', // Cyan
    '#FF6B9D'  // Pink
];

// === Global State ===
let particles = [];
let flowField = [];

function setup() {
    createCanvas(windowWidth, windowHeight);
    colorMode(HSB, 360, 100, 100, 100);

    // Initialize particles
    for (let i = 0; i < CONFIG.particleCount; i++) {
        particles.push(new Particle());
    }

    background(230, 60, 8); // Dark blue-black
}

function draw() {
    // Semi-transparent background for trails
    noStroke();
    fill(230, 60, 8, CONFIG.trailAlpha);
    rect(0, 0, width, height);

    // Update and display particles
    for (let p of particles) {
        p.update();
        p.display();
        p.edges();
    }
}

// === Particle Class ===
class Particle {
    constructor() {
        this.pos = createVector(random(width), random(height));
        this.vel = createVector(0, 0);
        this.acc = createVector(0, 0);
        this.maxSpeed = CONFIG.speed + random(0.5);
        this.color = color(random(PALETTE));
        this.size = random(1.5, 4);
        this.prevPos = this.pos.copy();
    }

    update() {
        // Calculate flow field force
        let angle = noise(this.pos.x * CONFIG.noiseScale, 
                         this.pos.y * CONFIG.noiseScale,
                         frameCount * 0.002) * TWO_PI * 4;

        let force = p5.Vector.fromAngle(angle);
        force.mult(0.3);

        this.applyForce(force);

        this.vel.add(this.acc);
        this.vel.limit(this.maxSpeed);
        this.pos.add(this.vel);
        this.acc.mult(0);
    }

    applyForce(force) {
        this.acc.add(force);
    }

    display() {
        stroke(this.color);
        strokeWeight(this.size);
        line(this.pos.x, this.pos.y, this.prevPos.x, this.prevPos.y);
        this.prevPos = this.pos.copy();
    }

    edges() {
        if (this.pos.x > width) { this.pos.x = 0; this.prevPos.x = 0; }
        if (this.pos.x < 0) { this.pos.x = width; this.prevPos.x = width; }
        if (this.pos.y > height) { this.pos.y = 0; this.prevPos.y = 0; }
        if (this.pos.y < 0) { this.pos.y = height; this.prevPos.y = height; }
    }
}

function windowResized() {
    resizeCanvas(windowWidth, windowHeight);
    background(230, 60, 8);
}

function keyPressed() {
    if (key === 's' || key === 'S') saveCanvas('crypto-flow', 'png');
    if (key === ' ') background(230, 60, 8); // Clear with spacebar
}
</script>
</body>
</html>'''

# Save the file
output_path = '/home/z/crypto-flow.html'
with open(output_path, 'w') as f:
    f.write(html_content)

print(f"✅ Generative art created!")
print(f"📁 File saved to: {output_path}")
print(f"\n🎨 Features:")
print(f"   • {CONFIG['particleCount']} flowing particles")
